const reviews = $input.all();
const thresholds = [4, 12, 24];
const alarms = [];

for (const item of reviews) {
  const r = item.json;
  const hours = parseFloat(r.hours_waiting);
  for (const threshold of thresholds) {
    // Eşiği tam geçtiyse alarm üret (1 saatlik pencerede)
    if (hours >= threshold && hours < threshold + 1) {
      alarms.push({
        json: {
          review_id: r.id,
          firm_id: r.firm_id,
          firm_name: r.firm_name,
          reviewer_name: r.reviewer_name,
          rating: r.rating,
          hours_waiting: Math.floor(hours),
          threshold,
          message: `${r.firm_name}: ${r.reviewer_name} tarafından ${r.rating} yıldızlı yorum ${Math.floor(hours)} saattir yanıtsız bekliyor.`
        }
      });
    }
  }
}

return alarms.length > 0 ? alarms : [{ json: { no_alarms: true } }];
